import type { Page } from '@playwright/test'
import type { ElementCheck } from './types'

export interface VerifyDetail {
  label: string
  selector: string
  passed: boolean
}

export interface VerifyResult {
  passed: number
  failed: number
  details: VerifyDetail[]
}

export async function verify(
  page: Page,
  checks: ElementCheck[],
): Promise<VerifyResult> {
  const details: VerifyDetail[] = []
  let passed = 0
  let failed = 0

  for (const check of checks) {
    let ok = false
    try {
      ok = await page.locator(check.selector).isVisible({ timeout: 3000 })
    } catch {
      ok = false
    }

    if (ok) {
      passed++
      console.log(`  PASS  ${check.label}`)
    } else {
      failed++
      console.log(`  FAIL  ${check.label}  (${check.selector})`)
    }

    details.push({ label: check.label, selector: check.selector, passed: ok })
  }

  return { passed, failed, details }
}

import type { Page } from '@playwright/test'

export type DemoMode = 'auto' | 'manual'

export interface ElementCheck {
  selector: string
  label: string
}

export interface DemoStep {
  title: string
  description: string
  action: (page: Page) => Promise<void>
  expect?: ElementCheck[]
}

export interface DemoOptions {
  mode: DemoMode
  pauseMs: number
  startStep: number
  browser: 'chromium' | 'firefox' | 'webkit'
  headless: boolean
}

